/* Medos Hotel — i18n.en.js (English translation strings) */ window._T_en = { 'site.name': 'Medos Hotel', 'site.tagline': 'Güzelçamlı, Kuşadası · Aegean', 'nav.home': 'Home', 'nav.rooms': 'Rooms', 'nav.rooms.standard': 'Standard Room', 'nav.rooms.family': 'Family Room', 'nav.rooms.suite': 'Family Suite', 'nav.virtual_tour': 'Virtual Tour', 'nav.places': 'Places to Visit', 'nav.places.ephesus': 'Ephesus Ancient City', 'nav.places.virgin_mary': 'House of Virgin Mary', 'nav.places.sirince': 'Şirince Village', 'nav.places.dilek': 'Dilek Peninsula', 'nav.places.zeus': 'Zeus Cave', 'nav.places.pigeon': 'Pigeon Island Castle', 'nav.about': 'About', 'nav.transport': 'Getting Here', 'nav.contact': 'Contact', 'footer.quicklinks': 'Quick Links', 'footer.contact_title': 'Contact', 'footer.location': 'Location', 'footer.view_map': 'View on Map', 'footer.address': 'Zeus Cumhuriyet Sk No: 5, Güzelçamlı Mh., 09430 Kuşadası, Aydın, Turkey', 'footer.copyright': 'All rights reserved.', 'footer.developed_by': 'Developed by', 'footer.developer': 'Designed and developed by <a href="https://decigent.com" target="_blank" rel="noopener noreferrer">Decigent Artificial Intelligence and Information Technologies</a>.', 'footer.documents': 'Documents', 'footer.cookie_policy': 'Cookie Policy', 'footer.privacy_notice': 'Privacy Notice', 'footer.kvkk_text': 'KVKK Text', 'footer.data_request': 'Data Request Form', 'footer.sustainability_report': 'Sustainability Report', 'footer.sustainability_corner': 'Sustainability Corner', 'footer.species_action_plan': 'Aydın Province Species Action Plan', 'footer.sustainability_cert': 'Sustainable Tourism Certificate', 'reviews.title': 'What Our Guests Say', 'reviews.heading': 'Guest Reviews', 'reviews.count': 'Google reviews', 'reviews.view_all': 'See All Reviews →', 'cta.chat': 'Your Assistant', 'cta.call': 'Call', 'cta.book': 'Book Now', 'btn.detail': 'Details', 'btn.book': 'Book Now', 'btn.explore': 'Explore the Hotel', 'btn.learn_more': 'Learn More', 'btn.back_home': 'Back to Home', 'btn.send': 'Send Message', 'btn.map': 'View on Map', 'breadcrumb.home': 'Home', 'breadcrumb.rooms': 'Rooms', 'breadcrumb.places': 'Places to Visit', 'hero.eyebrow': 'Güzelçamlı · Kuşadası · Aegean', 'hero.title': 'Sea sounds,<br>nature\'s embrace', 'hero.title2': 'Book early,<br>save up to 25%', 'about.label': 'Who We Are', 'about.title': 'Beachfront Family Hotel in Güzelçamlı', 'about.p1': 'Located in Güzelçamlı, the jewel of Kuşadası, on the Aegean coast, Medos Beach Hotel offers guests an unforgettable holiday experience with its beachfront location, nature-immersed atmosphere and comfortable facilities. An ideal choice for those looking for a hotel in Güzelçamlı, our hotel is ready to welcome guests year-round with <strong>49 rooms and 150 beds</strong> capacity, for both relaxation and exploration.', 'about.p2': 'Medos Beach Hotel, located in Güzelçamlı, one of Kuşadası\'s most peaceful areas, is just 2 km from <a href="dilek_yarim_adasi_milli_park.html">Dilek Peninsula National Park</a>. From our hotel you can quickly discover the park\'s unique coves, join nature walks, or enjoy swimming in the crystal-clear waters on <a href="kusadasi-tekne-turlari-rehberi.html">boat tours</a>. Surrounded by the natural beauty of Güzelçamlı, you can enjoy a peaceful holiday while easily reaching Kuşadası\'s vibrant centre and nearby historical sites.', 'about.p3': 'Standing out among <a href="guzelcamli-otel.html">accommodation options in Kuşadası Güzelçamlı</a> for its tranquillity, clean beach and family-friendly character, Medos Beach Hotel caters to guests of all ages with its comfortable rooms featuring modern design. From our French-balcony rooms you can watch the Aegean sunrise, and enjoy the sea at our private jetty just 50 metres from the hotel. Our hotel brings together peace, comfort and location advantages for guests seeking a beachfront hotel in Kuşadası.', 'about.p4': 'Medos Beach Hotel, standing out among Kuşadası Güzelçamlı hotel options, promises not just accommodation but a holistic holiday experience combining nature, sea, discovery and relaxation. If you are looking for a beachfront, comfortable and enjoyable hotel in Güzelçamlı, you can <a href="booking.html">browse our room options</a> or contact us at <a href="tel:+902566450740">+90 256 645 07 40</a>.', 'about.stat.rooms': 'Rooms', 'about.stat.beds': 'Beds', 'about.stat.distance': 'Dilek Park', 'rooms.heading': 'ROOMS', 'rooms.standard.name': 'Standard Room', 'rooms.standard.f1': 'Double Bed', 'rooms.standard.f2': 'AC · WiFi · TV', 'rooms.family.name': 'Family Room', 'rooms.family.f1': 'Double + Twin Beds', 'rooms.family.f2': 'Separate Bedroom · AC · WiFi', 'rooms.suite.name': 'Family Suite', 'rooms.suite.f1': 'Living Room + Bedroom', 'rooms.suite.f2': 'AC · WiFi · TV', 'services.heading': 'SERVICES', 'services.pool_adult.name': 'Adult Pool', 'services.pool_adult.desc': 'Renovated in 2024; 70 m² area, 140 cm depth.', 'services.pool_kids.name': 'Children\'s Pool', 'services.pool_kids.desc': 'Safe children\'s pool; 16 m² area, 40 cm depth.', 'services.wifi.name': 'Free WiFi', 'services.wifi.desc': 'High-speed internet in all rooms and common areas.', 'services.restaurant.name': 'Restaurant', 'services.restaurant.desc': 'Rich Aegean cuisine with buffet and à la carte options.', 'services.bar.name': 'Bar', 'services.bar.desc': 'Drinks and snacks at the poolside and dock bar.', 'services.snackbar.name': 'Snack Bar', 'services.snackbar.desc': 'Light meals and snacks served at the poolside.', 'services.boat.name': 'Boat Tour', 'services.boat.desc': 'Guided boat tour to the stunning coves of Dilek Peninsula.', 'services.yacht.name': 'Yacht Rental', 'services.yacht.desc': 'Rent a private yacht and freely explore the coves.', 'attractions.heading': 'Places to Visit', 'attractions.ephesus.name': 'Ephesus Ancient City', 'attractions.ephesus.desc': 'One of the best-preserved ancient cities in the world — a must-see open-air museum.', 'attractions.virgin_mary.name': 'House of Virgin Mary', 'attractions.virgin_mary.desc': 'Sacred pilgrimage site believed to be the last home of the Virgin Mary.', 'attractions.sirince.name': 'Şirince Village', 'attractions.sirince.desc': 'A charming village famous for its preserved architecture and fruit wines.', 'attractions.dilek.name': 'Dilek Peninsula', 'attractions.dilek.desc': 'National park with 209 bird species and crystal-clear coves.', 'attractions.zeus.name': 'Zeus Cave', 'attractions.zeus.desc': 'A mysterious natural cave steeped in Aphrodite mythology.', 'attractions.pigeon.name': 'Pigeon Island Castle', 'attractions.pigeon.desc': 'Historic castle built by Barbaros Hayrettin Pasha — the symbol of Kuşadası.', 'gallery.heading': 'Photo Gallery', 'page.standart.title': 'Standard Room', 'page.standart.info_title': 'About the Room', 'page.standart.info': 'Our Standard Rooms offer sea, partial sea, National Park or garden views and cover 21 m². Except for TRP rooms, beds can be configured as 2 single beds or 1 double bed upon request. All rooms feature air conditioning, a dressing table with mirror, wardrobes, a French balcony, bathroom and toilet, hair dryer, satellite TV and minibar. All rooms have laminate flooring. TRP rooms can be arranged as 1 double bed and 1 single bed, or 3 single beds. Extra beds are available in non-TRP rooms upon request, subject to availability and an additional charge.', 'page.standart.features_title': 'Room Amenities', 'page.standart.gallery_title': 'Room Photos', 'page.standart.capacity': '2–3 Guests', 'page.standart.size': '21 m²', 'page.standart.view': 'Sea or Garden View', 'page.standart.f1': 'Single/Double Bed', 'page.standart.f2': 'Air Conditioning', 'page.standart.f3': 'Free WiFi', 'page.standart.f4': 'Flat Screen TV', 'page.standart.f5': 'Private Bathroom', 'page.standart.f6': 'French Balcony', 'page.standart.f7': 'Minibar', 'page.standart.f9': 'Hair Dryer', 'page.standart.f10': 'Slippers', 'page.standart.f11': 'Toiletries', 'page.aile.title': 'Family Room', 'page.aile.info_title': 'About the Room', 'page.aile.info': 'Our Family Rooms consist of 2 interconnected bedrooms, each 45 m², with a maximum capacity of 5 guests. They offer sea, partial sea, National Park or garden views. Each room features air conditioning, a dressing table with mirror, wardrobes, a French balcony, bathroom and toilet, hair dryer, satellite TV and minibar. All rooms have laminate flooring.', 'page.aile.features_title': 'Room Amenities', 'page.aile.gallery_title': 'Room Photos', 'page.aile.capacity': '3–5 Guests', 'page.aile.size': '45 m²', 'page.aile.view': 'Garden & Mountain View', 'page.aile.f1': 'Single/Double Bed (Master)', 'page.aile.f2': '2–3 Single Beds (2nd Room)', 'page.aile.f3': 'Separate Bedrooms', 'page.aile.f4': 'Air Conditioning', 'page.aile.f5': 'Free WiFi', 'page.aile.f6': 'Flat Screen TV', 'page.aile.f7': 'Private Bathroom', 'page.aile.f9': 'Minibar', 'page.aile.f10': 'Toiletries', 'page.aile.f11': 'Hair Dryer', 'page.aile.f12': 'French Balcony', 'page.aile.f13': 'Slippers', 'page.suite.title': 'Family Suite', 'page.suite.info_title': 'About the Room', 'page.suite.info': 'Our Suite is 75 m² and consists of 2 interconnected bedrooms and a lounge with a seating area. The bedrooms overlook the National Park and the lounge has sea views. The suite features air conditioning, a dressing table with mirror, wardrobes, a French balcony, bathroom and toilet, hair dryer, satellite TV and minibar. With an extra bed, the suite accommodates up to 7 guests.', 'page.suite.features_title': 'Room Amenities', 'page.suite.gallery_title': 'Room Photos', 'page.suite.capacity': '4–6 Guests', 'page.suite.size': '75 m²', 'page.suite.view': 'Garden & Sea View', 'page.suite.f1': 'Single/Double Bed (Master)', 'page.suite.f2': '3 Single Beds (2nd Room)', 'page.suite.f3': 'Separate Bedrooms', 'page.suite.f4': 'Spacious Living Room', 'page.suite.f5': 'Air Conditioning', 'page.suite.f6': 'Free WiFi', 'page.suite.f7': 'Flat Screen TV', 'page.suite.f8': 'Private Bathroom', 'page.suite.f9': 'Minibar', 'page.suite.f10': 'French Balcony', 'page.suite.f11': 'Toiletries', 'page.suite.f12': 'Slippers', 'page.suite.f13': 'Hair Dryer', 'page.efes.title': 'Ephesus Ancient City', 'page.efes.info_title': 'About Ephesus', 'page.efes.info': '<p>Ephesus Ancient City is one of the most important cities of ancient Rome, located in the Selçuk district of İzmir province in western Turkey. In antiquity, Ephesus was known as a great harbour city and cultural centre. Today it is open to visitors with its archaeological remains and historical riches.</p><p>Founded in the 10th century BC, Ephesus was ruled by many civilisations including the Lydians, Persians, Macedonians and the Roman Empire. The city reached its peak during the Hellenistic and Roman periods and holds immense historical and cultural significance.</p><p>Ephesus contains many important ruins: the Temple of Artemis, the Library of Celsus, the Grand Theatre, the Fountain of Trajan and the Temple of Hadrian are among its most notable monuments. The Library of Celsus, one of the most famous structures in Ephesus, was one of the largest libraries of the ancient world. Its surviving façade remains remarkably impressive.</p><p>The Grand Theatre, with a capacity of over 25,000, is one of the most important theatres of antiquity and is still used today for concerts and events.</p><p>Located near Ephesus, this church — traditionally believed to mark the place where the Virgin Mary spent her final years — is a sacred pilgrimage site for Christians.</p><p>The museum adjacent to Ephesus displays artefacts uncovered during excavations in the region, including ancient sculptures, mosaics and other relics from antiquity.</p>', 'page.efes.activities_title': 'Things to Do', 'page.efes.a1': 'Visit the Library of Celsus', 'page.efes.a2': 'Experience the ancient acoustics of the Grand Theatre', 'page.efes.a3': 'Admire the mosaics in the Terrace Houses', 'page.efes.a4': 'See the ruins of the Temple of Artemis', 'page.efes.a5': 'Join a guided historical tour', 'page.efes.a6': 'Visit the Ephesus Museum in Selçuk', 'page.efes.distance': '30 km', 'page.meryem.title': 'House of Virgin Mary', 'page.meryem.info_title': 'About the House of Virgin Mary', 'page.meryem.info': '<p>The House of the Virgin Mary is situated on Mount Bülbül, 9 km from Selçuk. It is believed that St. John brought the Virgin Mary to Ephesus 4 or 6 years after the death of Jesus. In 1891, Lazarist priests, guided by the visions of German nun A. Katharina Emmerick, identified this house through research as the place where Mary spent her final days. This discovery was a landmark event for the Christian world and shed light on religious history worldwide. The cross-plan, domed structure was later restored. The house, also considered sacred by Muslims, has hosted masses every year on 15 August since Pope Paul VI\'s visit in 1967, drawing great interest from pilgrims around the world.</p>', 'page.meryem.activities_title': 'Things to Do', 'page.meryem.a1': 'Visit the sacred site and offer a prayer', 'page.meryem.a2': 'Tie a wish to the wishing wall', 'page.meryem.a3': 'Drink from and collect the holy spring water', 'page.meryem.a4': 'Take a nature walk on Mount Bülbül', 'page.meryem.a5': 'Combine with a nearby Ephesus tour', 'page.meryem.distance': '35 km', 'page.sirince.title': 'Şirince Village', 'page.sirince.info_title': 'About Şirince Village', 'page.sirince.info': '<p>Şirince is a historic and charming village located approximately 8 kilometres from the Selçuk district of İzmir province in western Turkey. In antiquity the village was known as "Kırkınca." During the Greek period it was called "Çirkince," before taking the name "Şirince" in 1926.</p><p>It sits at an elevated position above sea level, surrounded by vineyards on all sides.</p><p>Şirince is renowned for its stone houses built in typical Aegean architecture, its narrow streets and village squares. The village stands out for preserving its historic fabric with restored buildings.</p><p>Şirince is famous for its renowned vineyards and grape products. Organic wine is produced in the village. Şirince wines, olive oils and resin wines are among its most celebrated offerings.</p><p>Şirince attracts tourists with its historic atmosphere, natural beauty and local products. The village sees a surge of visitors especially at weekends and during the summer months.</p><p>Small shops selling traditional handicrafts and souvenirs can be found throughout the village. Various souvenirs such as local handicrafts, ceramic products and hand-woven goods are available.</p><p>Şirince Square is the central meeting point of the village. The square is home to various cafés, restaurants and souvenir shops. Visitors can enjoy traditional Turkish coffee and soak up the village atmosphere.</p>', 'page.sirince.activities_title': 'Things to Do', 'page.sirince.a1': 'Taste fruit wines and local spirits', 'page.sirince.a2': 'Shop for handmade souvenirs', 'page.sirince.a3': 'Walk along the cobblestone streets', 'page.sirince.a4': 'Discover the local Aegean cuisine', 'page.sirince.a5': 'Buy olive oil and natural products at the village market', 'page.sirince.distance': '49 km', 'page.dilek.title': 'Dilek Peninsula National Park', 'page.dilek.info_title': 'About Dilek Peninsula', 'page.dilek.info': 'The Dilek Peninsula–Büyük Menderes Delta National Park, just 2 km from Medos Hotel, is one of Turkey\'s most important nature reserves. Spanning 27,000 hectares, it is home to 209 bird species and wildlife ranging from Mediterranean monk seals to sea turtles. Four main coves offer clean and peaceful beaches.', 'page.dilek.activities_title': 'Things to Do', 'page.dilek.a1': 'Swim in crystal-clear coves', 'page.dilek.a2': 'Snorkel and discover the underwater world', 'page.dilek.a3': 'Trek along marked nature trails', 'page.dilek.a4': 'Go birdwatching (209 species!)', 'page.dilek.a5': 'Take a tour boat around the coves', 'page.dilek.a6': 'Visit Zeus Cave (inside the park)', 'page.dilek.distance': '2 km', 'page.dilek.coves_title': 'Coves', 'page.dilek.cove1_name': 'İçmeler Cove', 'page.dilek.cove1_dist': '1 km from entrance', 'page.dilek.cove1_desc': 'Sandy seabed with shallow water.', 'page.dilek.cove2_name': 'Aydınlık Cove', 'page.dilek.cove2_dist': '6 km from entrance', 'page.dilek.cove2_desc': 'Rocky seabed with very deep water.', 'page.dilek.cove3_name': 'Kavaklı', 'page.dilek.cove3_dist': '8 km from entrance', 'page.dilek.cove3_desc': 'Home to very tall trees, with a rocky shore and deep sea.', 'page.dilek.cove4_name': 'Karasu', 'page.dilek.cove4_dist': '11 km from entrance', 'page.dilek.cove4_desc': 'Rocky shore; the cove drops to considerable depth within just 1-2 steps, which is the origin of its name.', 'page.zeus.title': 'Zeus Cave', 'page.zeus.info_title': 'About Zeus Cave', 'page.zeus.info': '<p>Zeus Cave is one of the important natural and historical sites located within the Dilek Peninsula–Büyük Menderes Delta National Park in the Kuşadası district of Aydın province, Turkey. The cave holds mythological significance and is known as the place where Zeus is believed to have been born.</p><p>A chapel inside the cave and the natural formations within it attract visitors. According to mythological accounts, Zeus\'s mother Rhea gave birth to Zeus in the Dikili Taş Forest to save him from Cronus. During this birth, it was requested that the cave be sealed to protect Zeus. According to mythology, the cave where Zeus was born possesses a unique atmosphere and great historical depth.</p><p>As it lies within a national park, Zeus Cave draws attention not only for its natural beauty but also for its historical and mythological richness. The area can be an interesting destination for nature lovers, history enthusiasts and mythology admirers alike.</p>', 'page.zeus.activities_title': 'Things to Do', 'page.zeus.a1': 'Cool off in the crystal-clear, icy spring water', 'page.zeus.a2': 'Trek along the forest hiking trail', 'page.zeus.a3': 'Combine with other coves in the national park', 'page.zeus.a4': 'Enjoy nature photography', 'page.zeus.distance': '1 km', 'page.guvercin.title': 'Pigeon Island Castle', 'page.guvercin.info_title': 'About Pigeon Island Castle', 'page.guvercin.info': '<p>The island, located in the Kuşadası district, is connected to the mainland by a man-made causeway. A castle built by the Genoese stands on the island, which is an iconic landmark of Kuşadası. In 2020, UNESCO added the castle to its World Heritage Tentative List under the file "Genoese Commercial Route: Fortresses and Fortified Settlements from the Mediterranean to the Black Sea."</p><p>The Güvercinada Castle, which covers the entire island, sits on a natural rocky outcrop. Its history dates back to the Genoese, who arrived in Kuşadası in the late 13th or early 14th century, and it was later renovated during the Ottoman Empire. Because the island also served as an outpost against pirates during the Ottoman period, it is also known as the Pirate\'s Castle.</p><p>The inner citadel and the city arsenal on the island were built by Barbaros Hayreddin Pasha, appointed as the first governor-general of the Province of Cezayir-i Bahr-i Sefid established in 1533. After Kuşadası was granted as an estate to Grand Vizier and son-in-law Öküz Mehmed Pasha in 1613, he had the castle repaired. In the 19th century, the outer walls and the surrounding fortifications were repaired in 1826–1827 by subaşı İlyas Ağa during the Morean Revolt. The castle was again repaired and reinforced in 1834, connected to the mainland by a breakwater in 1957, and underwent further restoration in 2013 with several structures inside the castle being restored.</p>', 'page.guvercin.activities_title': 'Things to Do', 'page.guvercin.a1': 'Walk the historic walls and enjoy panoramic views', 'page.guvercin.a2': 'Watch the sunset over Kuşadası Bay', 'page.guvercin.a3': 'Take a boat tour around the island', 'page.guvercin.a4': 'Explore the Kuşadası bazaar and marina', 'page.guvercin.distance': '~8 km', 'page.about.title': 'About Us', 'page.about.hero_subtitle': 'A unique holiday experience for everyone', 'page.about.story_title': 'Our Story', 'page.about.story': 'Medos Hotel is a family-run establishment on the Aegean coast of Güzelçamlı, the tranquil and verdant cove of Kuşadası. Located in the heart of nature, away from city noise yet close to everything, it offers guests a unique holiday environment. You will feel the warmth of our family and the authenticity of the Aegean in every detail.', 'page.about.vision_title': 'Our Vision', 'page.about.vision': 'We want to offer our guests not just a place, but an experience. Our greatest desire is to welcome you year-round in Güzelçamlı, which renews itself with different beauty every season.', 'page.about.values_title': 'Our Values', 'page.about.v1_title': 'Reliability', 'page.about.v1_desc': 'We always deliver on our promises, guided by transparency and honesty.', 'page.about.v2_title': 'Guest Focus', 'page.about.v2_desc': 'We place guest satisfaction and comfort at the heart of every decision.', 'page.about.v3_title': 'Continuous Improvement', 'page.about.v3_desc': 'We embrace learning and growth to elevate our service quality every day.', 'page.about.v4_title': 'Innovation', 'page.about.v4_desc': 'We create a difference by generating creative and original solutions to changing needs.', 'page.about.v5_title': 'Social Responsibility', 'page.about.v5_desc': 'We act with awareness of our responsibilities towards society and the environment.', 'page.about.v6_title': 'Self-Criticism & Empathy', 'page.about.v6_desc': 'We empathise with others and learn from our mistakes to grow together.', 'page.about.v7_title': 'Taking Initiative', 'page.about.v7_desc': 'We take action without waiting for the perfect moment, moving forward with a solution-oriented mindset.', 'page.about.v8_title': 'Efficiency', 'page.about.v8_desc': 'We aim to generate the highest value by using our resources wisely.', 'page.about.policy_title': 'Our Policies', 'page.about.policy_commit': 'we commit.', 'page.about.p1': 'To fulfil our compliance obligations with legal and other relevant requirements,', 'page.about.p2': 'To ensure the availability of the knowledge and resources necessary to achieve management system objectives and targets,', 'page.about.p3': 'To safeguard the continuing satisfaction of our stakeholders by taking into account the needs and expectations of our guests and interested parties,', 'page.about.p4': 'To prevent errors that may arise in our activities and to eliminate identified sources of errors,', 'page.about.p5': 'To support the procurement of energy-efficient products and services that affect energy performance,', 'page.about.p6': 'To eliminate hazards that may arise during our activities and to reduce risks to occupational health and safety,', 'page.about.p7': 'To provide the safe and healthy working conditions necessary to prevent work-related injury and ill health arising from our activities,', 'page.about.p8': 'To consult and involve employees and employee representatives in our occupational health and safety activities,', 'page.about.p9': 'During and after the delivery of our services, to reduce environmental pollution and to use energy, natural resources and materials efficiently,', 'page.about.p10': 'To prevent pollution, to avoid negative environmental impacts arising from our activities and to increase recovery,', 'page.about.p11': 'At every stage of the food chain, to ensure the protection of product safety and quality by prioritising human health, and to offer standardised product quality by working in cooperation with our suppliers,', 'page.booking.title': 'Reservation', 'page.booking.hero_subtitle': 'Secure your spot right away', 'page.transport.title': 'Getting Here', 'page.transport.hero_subtitle': 'Transport Options to Güzelçamlı', 'page.transport.map_title': 'Location', 'page.contact.title': 'Contact', 'page.contact.hero_subtitle': 'We are here for your questions', 'page.contact.form_title': 'Send a Message', 'page.contact.name': 'Full Name', 'page.contact.email': 'Email Address', 'page.contact.phone': 'Phone (Optional)', 'page.contact.subject': 'Subject', 'page.contact.message': 'Your Message', 'page.contact.send': 'Send', 'page.contact.info_title': 'Contact Information', 'page.contact.address_title': 'Address', 'page.contact.phone_title': 'Phone', 'page.contact.email_title': 'Email', 'page.contact.hours_title': 'Reception Hours', 'page.contact.hours': '24 Hours / 7 Days', 'page.contact.form_success': 'Your message has been sent. We will get back to you as soon as possible.', 'page.tour.title': 'Virtual Tour', 'page.tour.hero_subtitle': 'Explore the hotel in 360°', 'page.tour.intro': 'Before visiting Medos Hotel, you can explore all our areas with our 360° virtual tour. Interactively walk through our rooms, pool area, restaurant and dock.', 'nav.blog': 'Blog', 'breadcrumb.blog': 'Blog', 'page.blog.title': 'Blog', 'page.blog.hero_subtitle': 'Travel Guide & News', 'blog.read_more': 'Read More →', 'blog.back': '← Back to Blog', 'blog.by': 'Medos Hotel', 'blog.related.title': 'Related Pages', 'blog.related.guzelcamli': 'Stay in Güzelçamlı', 'blog.related.denize_sifir': 'Kuşadası Beachfront Hotel', 'blog.related.dilek': 'Dilek Peninsula Guide', 'blog.related.tekne': 'Kuşadası Boat Tours Guide', 'blog.related.kusadasi': 'Places to Visit in Kuşadası', 'blog.related.efes': 'Ephesus Ancient City Guide', 'blog.kusadasi.title': 'Places to Visit in Kuşadası (2026 Updated Guide)', 'blog.kusadasi.date': 'April 17, 2026', 'blog.plaj.title': 'Güzelçamlı Beaches Guide', 'blog.plaj.date': 'April 20, 2026', 'blog.plaj.category': 'Beach Guide', 'blog.plaj.excerpt': 'Güzelçamlı beaches: Sevgi Beach, Dilek Peninsula coves and coastal information. A guide for a peaceful seaside holiday with clean water and a calm atmosphere.', 'blog.plaj.cta': 'Medos Beach Hotel is an ideal accommodation for easy access to Sevgi Beach and the nearby coves.', 'blog.plaj.body': '<p>Among Güzelçamlı\'s beaches, Sevgi Beach, the coves within <a href="dilek_yarim_adasi_milli_park.html">Dilek Peninsula National Park</a> and the Güzelçamlı coastline stand out. With its clean sea, calm atmosphere and nature-immersed setting, the area is a strong alternative for those seeking a peaceful seaside holiday. Guests staying at <a href="index.html">Medos Hotel</a> can easily reach all of these beaches.</p><h2>Places to swim in Güzelçamlı</h2><p>Güzelçamlı, with its calm atmosphere and clean sea, is one of the ideal areas around Kuşadası for those seeking a peaceful beach holiday. It offers a holiday experience close to nature, away from crowded beach environments. These qualities are a great advantage for those looking for <a href="guzelcamli-otel.html">accommodation in Güzelçamlı</a>.</p><h2>Sevgi Beach</h2><img src="img/sevgi-plaji-guzelcamli.webp" alt="Güzelçamlı Sevgi Beach coastal view" loading="lazy" width="1200" height="800"><p>Sevgi Beach, with its wide beach area, shaded spots and family-friendly atmosphere, is one of Güzelçamlı\'s most popular beaches. Offering a comfortable environment for both families with children and couples, the beach provides a calmer experience in the morning hours.</p><h2>Dilek Peninsula National Park Beaches</h2><img src="img/dilek-yarimadasi-koy.webp" alt="Dilek Peninsula coves and clear sea" loading="lazy" width="1200" height="800"><p>Locations such as Aydınlık, Karasu and İçmeler within the national park offer a more natural and clearer sea experience amid nature. These coves attract particular attention for their clean water and natural appearance; they are very popular in summer. Visiting early in the morning ensures a more comfortable experience.</p><h2>Güzelçamlı Coastline</h2><img src="img/guzelcamli-sahil.webp" alt="Güzelçamlı coastline general view" loading="lazy" width="1200" height="800"><p>The Güzelçamlı coastline, close to the centre and ideal for daily sea enjoyment, appeals to holidaymakers of all ages. For those looking for <a href="kusadasi-denize-sifir-otel.html">beachfront accommodation</a>, the area is a very strong option.</p><h2>Hidden coves by boat tour</h2><img src="img/guzelcamli-tekne-turu-koy.webp" alt="Cove reached by Güzelçamlı boat tour" loading="lazy" width="1200" height="800"><p>With boat tours departing from Güzelçamlı, it is possible to reach coves that are difficult to access by land. These tours are an enjoyable activity that enriches the holiday for both families with children and couples. For detailed information, you can check the <a href="kusadasi-tekne-turlari-rehberi.html">Kuşadası Boat Tours Guide</a>.</p><h2>Why are Güzelçamlı beaches preferred?</h2><p>With its clean sea, calm atmosphere, family-friendly character and nature-immersed location, Güzelçamlı beaches offer a strong alternative to crowded holiday resorts. They are particularly ideal for those seeking a peaceful and quality seaside holiday.</p><h2>Frequently Asked Questions</h2><p><strong>Which is the most beautiful beach in Güzelçamlı?</strong><br>Sevgi Beach and the coves within the national park are among the most preferred options.</p><p><strong>Is Sevgi Beach suitable for families?</strong><br>Yes, it is a very suitable option for families due to its shaded areas and comfortable setting.</p>', 'blog.efes.title': 'Ephesus Ancient City Visit Guide', 'blog.efes.date': 'April 20, 2026', 'blog.efes.category': 'History Guide', 'blog.efes.excerpt': 'Ephesus guide: Library of Celsus, ancient theatre, marble street and how to get there from Kuşadası. Day trip tips from Güzelçamlı.', 'blog.efes.cta': 'Combine your Ephesus visit with sea and relaxation — Medos Beach Hotel offers an ideal stay in Güzelçamlı.', 'blog.efes.body': '<p>Ephesus Ancient City, with its proximity to Kuşadası, the Library of Celsus, ancient theatre and marble streets, is one of Turkey\'s most impressive historical destinations. Staying at <a href="index.html">Medos Hotel</a>, you can enjoy the tranquillity of Güzelçamlı while easily visiting Ephesus as a day trip.</p><h2>Where is Ephesus Ancient City?</h2><p>Ephesus is located in the Selçuk district, approximately 30 km from <a href="guzelcamli-otel.html">Güzelçamlı</a> and Kuşadası. This distance is very manageable for a day trip, either by private vehicle or organised tour.</p><h2>How to get to Ephesus?</h2><p>From Kuşadası and Güzelçamlı, you can reach Ephesus by private car in about 30 minutes, join organised day tours departing from the area, or plan your own route. For guests at a <a href="kusadasi-denize-sifir-otel.html">beachfront hotel in Kuşadası</a>, both options are very convenient.</p><h2>Library of Celsus</h2><img src="img/efes-celsus-kutuphanesi.webp" alt="Ephesus Library of Celsus facade" loading="lazy" width="1200" height="800"><p>The Library of Celsus, the most iconic structure of Ephesus, dates from the Roman period and is counted among the best-preserved ancient buildings in the world. A must-see during any visit, it also offers an exceptional opportunity for photography enthusiasts.</p><h2>Ancient Theatre</h2><img src="img/efes-antik-tiyatro.webp" alt="Ephesus Ancient Theatre general view" loading="lazy" width="1200" height="800"><p>With a capacity of approximately 25,000 people, the ancient theatre is one of the structures that best conveys the grandeur of Ephesus. Looking out from the theatre, it is possible to appreciate the overall layout of the ancient city.</p><h2>Marble Street</h2><img src="img/efes-mermer-cadde.webp" alt="Ephesus Ancient City marble street" loading="lazy" width="1200" height="800"><p>The Marble Street, one of the areas that best reflects the atmosphere of Ephesus, was one of the main arteries of the ancient city. Walking along it, you can sense two thousand years of history. Early mornings see fewer crowds and offer far better light for photography.</p><h2>How long does an Ephesus visit take?</h2><p>An average of 2–3 hours is sufficient for a comfortable visit to Ephesus. For a more detailed tour, we recommend arriving early in the morning and considering a guided tour option.</p><h2>Best time to visit Ephesus</h2><p>In summer, early morning hours are the ideal time both to avoid crowds and for photography. Spring and autumn months offer milder weather conditions, making them even more suitable for sightseeing.</p><h2>Why stay in Güzelçamlı for Ephesus?</h2><p>For those who want to combine an Ephesus visit with a beach holiday, <a href="guzelcamli-otel.html">Medos Hotel in Güzelçamlı</a> is an ideal choice. Easy access to Ephesus combined with proximity to <a href="dilek_yarim_adasi_milli_park.html">Dilek Peninsula National Park</a> makes our hotel one of the most well-rounded accommodation options in the region.</p><h2>Frequently Asked Questions</h2><p><strong>How long does it take to visit Ephesus?</strong><br>An average of 2–3 hours is sufficient. A more comprehensive visit may take up to 4 hours.</p><p><strong>Is it easy to get to Ephesus from Kuşadası?</strong><br>Yes, it is approximately 30 km away and very suitable for a day trip by private vehicle or tour.</p>', 'blog.kusadasi.category': 'Travel Guide', 'blog.kusadasi.excerpt': 'Discover the most popular places to visit near Kuşadası: Dilek Peninsula National Park, Zeus Cave and Pigeon Island Castle.', 'blog.kusadasi.cta': 'Stay at Medos Beach Hotel and reach all these locations with ease.', 'blog.tekne.title': 'Kuşadası Boat Tours Guide', 'blog.tekne.date': 'April 18, 2026', 'blog.tekne.category': 'Activity Guide', 'blog.tekne.excerpt': 'Discover boat tours, one of Kuşadası\'s most enjoyable holiday activities. Güzelçamlı departures, hidden coves and breathtaking Aegean views.', 'blog.tekne.cta': 'You can easily join boat tours directly from our hotel.', 'blog.tekne.body': '<p>Kuşadası boat tours are among the most enjoyable activities of a summer holiday. Tours planned from around Güzelçamlı stand out in particular, offering faster access to coves and a more natural route experience. For guests staying at <a href="index.html">Medos Hotel</a>, this experience can be one of the unforgettable parts of the holiday.</p><h2>What to do on a Kuşadası boat tour?</h2><p>Boat tours typically include swimming stops at different coves, enjoying the sea and sun throughout the day. Some routes also offer opportunities for sightseeing, photography, and relaxing in tranquil coves.</p><h2>Coves and sea experience</h2><img src="img/kusadasi-tekne-turu-koy.webp" alt="Kuşadası boat tour cove and turquoise sea view" loading="lazy" width="1200" height="800"><p>The most important detail that makes a boat tour special is the ability to see coves that are difficult to reach by land. For this reason, it is a very strong alternative for those who want to explore the region from the sea.</p><h2>Why are swimming stops so popular?</h2><img src="img/tekne-turu-yuzme-molasi.webp" alt="Kuşadası boat tour swimming stop" loading="lazy" width="1200" height="800"><p>Swimming stops in coves with clean and clear water become one of the most enjoyable moments of the holiday, especially on hot summer days. It is also a very attractive activity for families with children and couples.</p><h2>Where is it more advantageous to stay for a boat tour?</h2><p>Staying in an area close to the boat tour provides convenience in terms of planning. That is why <a href="guzelcamli-otel.html">Medos Hotel in Güzelçamlı</a> stands out especially in summer. The area is also quite suitable for guests looking for a <a href="kusadasi-denize-sifir-otel.html">beachfront hotel</a>.</p>', 'blog.dilek.title': 'Dilek Peninsula National Park Guide', 'blog.dilek.date': 'April 18, 2026', 'blog.dilek.category': 'Nature Guide', 'blog.dilek.excerpt': 'Dilek Peninsula National Park guide: coves, hiking trails, nature and visit tips. Comprehensive information for guests staying in Güzelçamlı.', 'blog.dilek.cta': 'Medos Beach Hotel\'s location, just minutes from the national park, gives you a real advantage.', 'blog.dilek.body': '<p>Dilek Peninsula National Park is one of Güzelçamlı\'s most important natural assets. With its crystal-clear coves, rich vegetation and hiking areas, it ranks among the region\'s most remarkable routes. For guests staying at <a href="index.html">Medos Hotel</a>, a visit to the national park can be one of the most enjoyable parts of their holiday.</p><h2>Why is Dilek Peninsula so special?</h2><p>The national park is uniquely special as it brings together the sea, forest and wildlife in one location. If you don\'t want to limit your Güzelçamlı holiday to just the beach, this park is a must on your list.</p><h2>The most popular coves</h2><img src="img/dilek-yarimadasi-koylar.webp" alt="Dilek Peninsula turquoise coves" loading="lazy" width="780" height="439"><p>The coves within the park stand out especially for their clean water and natural appearance. They are very popular with day-trippers during the summer season. Arriving in the morning hours generally provides a more relaxed experience.</p><h2>Hiking and nature experience</h2><img src="img/dilek-yarimadasi-yuruyus-rotasi.webp" alt="Dilek Peninsula hiking trail and nature path" loading="lazy" width="780" height="439"><p>For nature hiking enthusiasts, the park offers a truly satisfying experience. It is a region rich in both scenery and wildlife. Guests staying in Güzelçamlı can plan their day with a balanced mix of sea and nature.</p><h2>Where is the best place to stay for a national park visit?</h2><p>Staying close to the national park provides a great advantage. For those who want to set off early in the morning, <a href="guzelcamli-otel.html">Medos Hotel in Güzelçamlı</a> is the far more sensible option. This area is also a very strong choice for guests looking for a <a href="kusadasi-denize-sifir-otel.html">beachfront hotel</a>.</p>', 'blog.kusadasi.excerpt': 'Discover places to visit in Kuşadası. An up-to-date travel guide to Dilek Peninsula National Park, Zeus Cave, Pigeon Island Castle and more.', 'blog.kusadasi.body': '<p>Kuşadası is one of the Aegean\'s most beloved holiday destinations, with its sea, historical sites and natural beauty. For guests who want to do more than swim during their holiday, there are many great alternatives. Staying at <a href="index.html">Medos Hotel</a>, you can experience the tranquil atmosphere of Güzelçamlı while easily reaching the important sights around Kuşadası.</p><h2>What are the main places to visit in Kuşadası?</h2><p>The main places to visit in Kuşadası are <a href="dilek_yarim_adasi_milli_park.html">Dilek Peninsula National Park</a>, <a href="zeus_magarasi.html">Zeus Cave</a>, <a href="guvercin_ada_kalesi.html">Pigeon Island Castle</a>, <a href="sirince_koyu.html">Şirince Village</a> and <a href="efes_antik_kenti.html">the historical sites around Ephesus</a>. <a href="guzelcamli-otel.html">Güzelçamlı and its surroundings</a> are a particularly strong option for visitors seeking nature and tranquillity.</p><h2><a href="dilek_yarim_adasi_milli_park.html">Dilek Peninsula National Park</a></h2><p>One of the region\'s most striking natural areas, the Dilek Peninsula stands out with its crystal-clear coves and nature hiking opportunities. Guests staying in Güzelçamlı will find it very easy to reach. For more details, see our <a href="dilek-yarimadasi-milli-park-rehberi.html">Dilek Peninsula guide</a>.</p><h2><a href="guvercin_ada_kalesi.html">Pigeon Island Castle</a></h2><img src="img/guvercinada-kalesi-kusadasi.webp" alt="Kuşadası Pigeon Island Castle view" loading="lazy" width="780" height="439"><p>Located in the centre of Kuşadası, Pigeon Island is well worth a visit for both its history and its views. It is particularly impressive in the evening hours.</p><h2><a href="zeus_magarasi.html">Zeus Cave</a></h2><img src="img/zeus-magarasi-kusadasi.webp" alt="Blue water view inside Zeus Cave" loading="lazy" width="780" height="439"><p>Zeus Cave attracts great interest especially in summer with its cool water and natural atmosphere. It is also a popular short stop for visitors exploring the national park area.</p><h2>Why is Güzelçamlı the right base?</h2><p>For those who want to explore Kuşadası without being in the middle of the crowds, Güzelçamlı is a well-balanced choice. It offers proximity to nature, the sea, and a calmer atmosphere. Medos Hotel is therefore a strong option for guests looking to <a href="guzelcamli-otel.html">stay in Güzelçamlı</a>.</p>', };